        String s = ep.trim();
        if (!s.startsWith("http://") && !s.startsWith("https://")) {
            s = "https://" + s;
        }
        // strip trailing slash
        while (s.endsWith("/")) s = s.substring(0, s.length() - 1);
        return s;
