    private static String sanitizeDomain(String domain) {
        if (isBlank(domain)) return null;
        String d = domain.trim();
        // Remove trailing slash for consistency; scheme is allowed, will be stripped when building
        while (d.endsWith("/")) d = d.substring(0, d.length() - 1);
        return d.isEmpty() ? null : d;
    }

    private static String stripScheme(String urlOrHost) {
        String s = urlOrHost;
        if (s.startsWith("http://")) return s.substring("http://".length());
        if (s.startsWith("https://")) return s.substring("https://".length());
        return s;
        }

    private static String extractHost(String url) {
        String s = stripScheme(url);
        int slash = s.indexOf('/');
        if (slash >= 0) s = s.substring(0, slash);
        // also trim any trailing slash
        while (s.endsWith("/")) s = s.substring(0, s.length() - 1);
        return s;
    }

    private static String percentEncodePath(String path) {
        StringBuilder sb = new StringBuilder(path.length() + 16);
        for (int i = 0; i < path.length(); i++) {
            char c = path.charAt(i);
            if (c == '/') {
