            case "csv": return "text/csv; charset=utf-8";
            case "jpg":
            case "jpeg": return "image/jpeg";
            case "png": return "image/png";
            case "gif": return "image/gif";
            case "webp": return "image/webp";
            case "svg": return "image/svg+xml";
            case "bmp": return "image/bmp";
            case "ico": return "image/x-icon";
            case "pdf": return "application/pdf";
            case "zip": return "application/zip";
            case "gz":
            case "gzip": return "application/gzip";
            case "rar": return "application/vnd.rar";
            case "7z": return "application/x-7z-compressed";
            case "tar": return "application/x-tar";
            case "mp4": return "video/mp4";
            case "webm": return "video/webm";
            case "mov": return "video/quicktime";
            case "mp3": return "audio/mpeg";
            case "wav": return "audio/wav";
            case "ogg": return "audio/ogg";
            default: return "application/octet-stream";
        }
    }

    // 读取必需配置（优先系统属性，其次环境变量），缺失则抛异常
    private static String requireConfig(String propKey, String envKey, String displayName) {
        String value = firstNonBlank(System.getProperty(propKey), System.getenv(envKey));
        if (isBlank(value)) {
            String msg = String.format("缺少必需配置：%s（System property: %s 或 Env: %s）", displayName, propKey, envKey);
            LOGGER.severe(msg);
            throw new IllegalStateException(msg);
        }
        return value.trim();
    }

    // 从若干候选中返回第一个非空且非空白的值
    private static String firstNonBlank(String... candidates) {
        if (candidates == null) return null;
        for (String c : candidates) {
            if (!isBlank(c)) {
                return c.trim();
            }
        }
        return null;
    }

    private static boolean isBlank(String s) {
        return s == null || s.trim().isEmpty();
    }
}

